from datetime import datetime, timedelta
from typing import Optional

from jose import jwt
from passlib.context import CryptContext
from fastapi import Depends, HTTPException, status
from fastapi.security import OAuth2PasswordBearer
import config

SECRET_KEY = config.SECRET_KEY
ALGORITHM = config.ALGORITHM
ACCESS_TOKEN_EXPIRE_MINUTES = config.ACCESS_TOKEN_EXPIRE_MINUTES

pwd_context = CryptContext(
    schemes=["argon2", "bcrypt"],
    deprecated="auto",
    # OWASP-recommended Argon2id params (2025): time_cost=2 iterations,
    # memory_cost=19456 KiB (~19 MiB), parallelism=1.
    argon2__time_cost=2,
    argon2__memory_cost=19456,
    argon2__parallelism=1,
)
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="login")


def verify_password(plain_password, hashed_password):
    """Verify a password against any supported scheme. Argon2 first (new
    standard), bcrypt second (legacy — auto-upgraded by needs_rehash on
    the next successful login). Falls through to test-account formats
    last for back-compat with legacy seed users."""
    try:
        return pwd_context.verify(plain_password, hashed_password)
    except Exception:
        pass
    import hashlib
    if hashlib.sha256(plain_password.encode()).hexdigest() == hashed_password:
        return True
    try:
        import crypt
        return crypt.crypt(plain_password, hashed_password) == hashed_password
    except Exception:
        return False


def needs_rehash(hashed_password):
    """True if this hash uses a deprecated scheme (e.g. bcrypt) and should
    be re-hashed with the current default (argon2id) on the next successful
    login."""
    try:
        return pwd_context.needs_update(hashed_password)
    except Exception:
        return True


def get_password_hash(password):
    """Hash a password with the default scheme (argon2id, since it's
    listed first in CryptContext.schemes)."""
    return pwd_context.hash(password)

def create_access_token(data: dict, expires_delta: Optional[timedelta] = None):
    to_encode = data.copy()
    expire = datetime.utcnow() + (expires_delta or timedelta(minutes=15))
    to_encode.update({"exp": expire})
    return jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)

def get_current_user(token: str = Depends(oauth2_scheme)):
    credentials_exception = HTTPException(
        status_code=status.HTTP_401_UNAUTHORIZED,
        detail="Could not validate credentials",
        headers={"WWW-Authenticate": "Bearer"},
    )
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        username: str = payload.get("sub")
        if username is None:
            raise credentials_exception
    except jwt.JWTError:
        raise credentials_exception
    return username

@router.post("/login", response_model=Token)
async def login_user(
    form_data: Annotated[OAuth2PasswordRequestForm, Depends()],
    db: Session = Depends(get_db)
):
    """Login user and return JWT token. Password verify is wrapped in a
    semaphore (cap = 20) so a login storm can't consume unbounded memory
    via concurrent argon2 verifies (each ~19 MiB peak)."""
    global _login_total_pending
    _login_total_pending += 1
    queued = max(0, _login_total_pending - _LOGIN_CONCURRENCY)
    if queued > _LOGIN_QUEUE_LOG_THRESHOLD:
        print(
            f"[login] high contention: total_pending={_login_total_pending} "
            f"in_flight≈{_LOGIN_CONCURRENCY} queued≈{queued}"
        )
    try:
        async with _login_sem:
            user = authenticate_user(db, form_data.username, form_data.password)
    finally:
        _login_total_pending -= 1
    if not user:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Incorrect username or password",
            headers={"WWW-Authenticate": "Bearer"},
        )

    access_token_expires = timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    access_token = create_access_token(
        data={"sub": user.username}, expires_delta=access_token_expires
    )

    return {"access_token": access_token, "token_type": "bearer"}

@router.get("/hello", response_model=HelloResponse)
async def protected_hello(current_user: User = Depends(get_current_user)):
    """Protected endpoint that requires authentication."""
    return {
        "message": f"Hello, {current_user.username}! This is a protected endpoint.",
        "user": current_user
    }

@router.get("/users/me", response_model=ProfileResponse)
async def get_my_profile(
    current_user: User = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """Return the current logged-in user's full profile."""
    photo = db.query(UserPhoto).filter(UserPhoto.user_id == current_user.id).first()

