def _validate_enum(value, allowed, field_name):
    if value is not None and value not in allowed:
        raise HTTPException(
            status_code=400,
            detail=f"{field_name} must be one of: {sorted(allowed)}",
        )


def _validate_range(value, lo, hi, field_name):
    if value is not None and not (lo <= value <= hi):
        raise HTTPException(
            status_code=400,
            detail=f"{field_name} must be between {lo} and {hi}",
        )


